svg.script:
var SVG_NS = "http://www.w3.org/2000/svg";
var XLINK  = "http://www.w3.org/1999/xlink";

var state = {
  loggedIn: false,
  dropdownOpen: false,
  modalOpen: false,
  labelsOn: true,
  page: "feed",          // "feed" | "other"
  // subscribed jurisdictions: persisted to a cookie (works logged-out).
  // `included` drives the unified-feed filter.
  subs: [{ name: "Global", icon: "#ic-globe", included: true }]
};

function $(id) { return document.getElementById(id); }
function show(el, on) { el.setAttribute("display", on ? "inline" : "none"); }

function icon(href, x, y, size, stroke) {
  var u = document.createElementNS(SVG_NS, "use");
  u.setAttribute("href", href);
  u.setAttributeNS(XLINK, "href", href);
  u.setAttribute("x", x); u.setAttribute("y", y);
  u.setAttribute("width", size); u.setAttribute("height", size);
  u.setAttribute("stroke", stroke);
  return u;
}
function txt(x, y, s, size, fill) {
  var t = document.createElementNS(SVG_NS, "text");
  t.setAttribute("x", x); t.setAttribute("y", y);
  t.setAttribute("font-size", size || 15);
  t.setAttribute("fill", fill || "#333");
  t.textContent = s;
  return t;
}
function rect(x, y, w, h, rx, fill, stroke) {
  var r = document.createElementNS(SVG_NS, "rect");
  r.setAttribute("x", x); r.setAttribute("y", y);
  r.setAttribute("width", w); r.setAttribute("height", h);
  r.setAttribute("rx", rx); r.setAttribute("fill", fill);
  if (stroke) r.setAttribute("stroke", stroke);
  return r;
}

// ---- jurisdiction dropdown interior (built from state.subs) -------------
var DD_X = 28, DD_W = 236, DD_TOP = 106, ROW_H = 40, PAD = 8;

function buildDropdown() {
  var inner = $("ddInner");
  while (inner.firstChild) inner.removeChild(inner.firstChild);

  // checkboxes only make sense once there is more than one jurisdiction to filter
  var hasCheckbox = state.subs.length > 1;
  var iconX = hasCheckbox ? DD_X + 40 : DD_X + 16;
  var nameX = hasCheckbox ? DD_X + 66 : DD_X + 42;

  var y = DD_TOP + PAD;
  state.subs.forEach(function (item) {
    var rowY = y;
    var row = document.createElementNS(SVG_NS, "g");
    row.style.cursor = "pointer";
    row.appendChild(rect(DD_X + 4, rowY, DD_W - 8, ROW_H, 8, "#ffffff"));

    // tapping a row (its name) switches the feed to ONLY that jurisdiction
    row.addEventListener("click", function () { selectOnly(item); });

    if (hasCheckbox) {
      // include checkbox toggles multi-select inclusion (overrides the row's select-only)
      var cb = document.createElementNS(SVG_NS, "g");
      cb.style.cursor = "pointer";
      cb.appendChild(rect(DD_X + 12, rowY + 11, 18, 18, 4, item.included ? "#333" : "#ffffff", "#333"));
      if (item.included) cb.appendChild(icon("#ic-check", DD_X + 13, rowY + 12, 16, "#ffffff"));
      cb.addEventListener("click", function (e) {
        e.stopPropagation();
        var includedCount = state.subs.filter(function (s) { return s.included; }).length;
        if (item.included && includedCount <= 1) return; // keep ≥1 selected (never None)
        item.included = !item.included;
        render();
      });
      row.appendChild(cb);
    }

    // jurisdiction icon + name
    row.appendChild(icon(item.icon, iconX, rowY + 11, 18, "#333"));
    row.appendChild(txt(nameX, rowY + 25, item.name, 15, "#333"));

    // external-open (jurisdiction page — deferred no-op)
    var ext = icon("#ic-external", DD_X + DD_W - 34, rowY + 11, 18, "#666");
    ext.style.cursor = "pointer";
    ext.addEventListener("click", function (e) { e.stopPropagation(); });
    row.appendChild(ext);

    inner.appendChild(row);
    y += ROW_H;
  });

  // full-width "+ Add Jurisdiction" button
  var addY = y + 4;
  var btn = document.createElementNS(SVG_NS, "g");
  btn.style.cursor = "pointer";
  var bRect = rect(DD_X + 8, addY, DD_W - 16, 36, 8, "#f2f2f2", "#333");
  bRect.setAttribute("stroke-dasharray", "4 3");
  btn.appendChild(bRect);
  btn.appendChild(icon("#ic-plus", DD_X + 44, addY + 10, 16, "#333"));
  var bt = txt(DD_X + DD_W / 2 + 10, addY + 23, "Add Jurisdiction", 14, "#333");
  bt.setAttribute("text-anchor", "middle");
  btn.appendChild(bt);
  btn.addEventListener("click", openModal);
  inner.appendChild(btn);

  $("ddBg").setAttribute("height", (addY + 36 + PAD) - DD_TOP);
}

function pillLabel() {
  var inc = state.subs.filter(function (s) { return s.included; });
  if (inc.length === 0) return "None";
  if (inc.length === 1) return inc[0].name;
  return inc.length + " selected";
}

// tap a jurisdiction name → switch the feed to ONLY that one (deselect the rest)
function selectOnly(item) {
  state.subs.forEach(function (s) { s.included = (s === item); });
  state.dropdownOpen = false;
  render();
}

// ---- modal ---------------------------------------------------------------
function openModal() { state.modalOpen = true; state.dropdownOpen = false; render(); }
function closeOverlays() { state.modalOpen = false; state.dropdownOpen = false; render(); }

// ---- main render ---------------------------------------------------------
function render() {
  // auth state + its callout
  show($("loginGlyph"), !state.loggedIn);
  show($("profileGlyph"), state.loggedIn);
  $("authCircle").setAttribute("fill", state.loggedIn ? "#333" : "#ffffff");
  $("annoLoginA").textContent = state.loggedIn ? "Signed in (avatar shown)" : "Logged out";
  $("annoLoginB").textContent = state.loggedIn ? "tap → profile (L to toggle)" : "tap → sign in (L to toggle)";

  // selector label reflects the unified-feed filter
  $("curJur").textContent = pillLabel();

  // dropdown
  if (state.dropdownOpen) buildDropdown();
  show($("dropdown"), state.dropdownOpen);
  show($("modal"), state.modalOpen);

  // fab icon + callout depend on the current page
  show($("fabCompose"), state.page === "feed");
  show($("fabFeed"), state.page !== "feed");
  $("annoFabA").textContent = state.page === "feed" ? "On Feed" : "On another page";
  $("annoFabB").textContent = state.page === "feed" ? "tap → compose a post (quill)" : "tap → go to Feed (list)";

  // labels: chrome always (when on); dropdown/modal only while open;
  // the include-filter callout only when checkboxes are actually shown
  show($("anno-chrome"), state.labelsOn);
  show($("anno-dropdown"), state.labelsOn && state.dropdownOpen);
  show($("anno-dd-filter"), state.labelsOn && state.dropdownOpen && state.subs.length > 1);
  show($("anno-modal"), state.labelsOn && state.modalOpen);
}

// ---- wiring --------------------------------------------------------------
$("selectorBtn").addEventListener("click", function () { state.dropdownOpen = !state.dropdownOpen; render(); });
$("authBtn").addEventListener("click", function () { state.loggedIn = !state.loggedIn; render(); });
$("fab").addEventListener("click", function () { state.page = (state.page === "feed") ? "other" : "feed"; render(); });
$("modalBackdrop").addEventListener("click", closeOverlays);
$("resultAlberta").addEventListener("click", function () {
  if (!state.subs.some(function (s) { return s.name === "Alberta"; })) {
    state.subs.push({ name: "Alberta", icon: "#ic-building", included: true });
  }
  state.modalOpen = false;
  state.dropdownOpen = true; // reopen list so the new entry is visible
  render();
});

document.addEventListener("keydown", function (e) {
  switch (e.key) {
    case "l": case "L": state.loggedIn = !state.loggedIn; render(); break;
    case "v": case "V": state.labelsOn = !state.labelsOn; render(); break;
    case "j": case "J": state.dropdownOpen = !state.dropdownOpen; render(); break;
    case "a": case "A": openModal(); break;
    case "p": case "P": state.page = (state.page === "feed") ? "other" : "feed"; render(); break;
    case "Escape": closeOverlays(); break;
  }
});

render();
